WITH TeacherBadgeUsers AS (
    SELECT UserId FROM badges WHERE Name = 'Teacher'
),
HighScoreCommentUsers AS (
    SELECT UserId FROM comments WHERE Score >= 5
),
UserDetails AS (
    SELECT U.Id, U.DisplayName, U.Reputation FROM users U
)
SELECT TBU.UserId AS user_id, UD.DisplayName AS display_name, UD.Reputation AS reputation
FROM TeacherBadgeUsers TBU
INNER JOIN HighScoreCommentUsers HSCU ON TBU.UserId = HSCU.UserId
INNER JOIN UserDetails UD ON TBU.UserId = UD.Id;

